import{c as e,Q as o,j as i,m as r}from"./chunks/framework.BPKcPtvA.js";const k=JSON.parse('{"title":"SOP Operativna Uputstva","description":"Standardne operativne procedure (SOP) za pokretanje, konfigurisanje i otklanjanje grešaka u radu orkestratora","frontmatter":{"title":"SOP Operativna Uputstva","description":"Standardne operativne procedure (SOP) za pokretanje, konfigurisanje i otklanjanje grešaka u radu orkestratora","keywords":"SOP, runbook, operational guide, setup protocol, troubleshooting guide","robots":"index, follow"},"headers":[],"relativePath":"sop/index.md","filePath":"sop/index.md","lastUpdated":null}'),t={name:"sop/index.md"};function n(s,a,p,l,u,d){return o(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="📋-sop-operativna-uputstva" tabindex="-1">📋 SOP Operativna Uputstva <a class="header-anchor" href="#📋-sop-operativna-uputstva" aria-label="Permalink to &quot;📋 SOP Operativna Uputstva&quot;">​</a></h1><p>Dobrodošli u odeljak za <strong>Standardne Operativne Procedure (SOP)</strong>. Ovde se nalaze detaljni koraci i operativni priručnici (Runbooks) namenjeni inženjerima za pouzdanost sistema (SRE) i administratorima za upravljanje i održavanje <strong>AI Workflow Orchestrator</strong> sistema.</p><hr><h2 id="🗂️-sadrzaj-operativnih-vodica" tabindex="-1">🗂️ Sadržaj Operativnih Vodiča <a class="header-anchor" href="#🗂️-sadrzaj-operativnih-vodica" aria-label="Permalink to &quot;🗂️ Sadržaj Operativnih Vodiča&quot;">​</a></h2><p>Operativna uputstva su podeljena u dve ključne kategorije:</p><h3 id="_1-sop-001-instalacija-setup-vodic" tabindex="-1">1. <a href="/sop/setup">SOP-001: Instalacija &amp; Setup Vodič</a> <a class="header-anchor" href="#_1-sop-001-instalacija-setup-vodic" aria-label="Permalink to &quot;1. [SOP-001: Instalacija &amp; Setup Vodič](/sop/setup)&quot;">​</a></h3><p>Kompletan vodič za inicijalno pokretanje sistema, podešavanje API ključeva, konfigurisanje baze podataka i bezbednosne pre-kondicije.</p><ul><li><strong>Ključne teme:</strong> Rotacija API ključeva, definisanje token limita, integracija sa MongoDB Atlasom i zaobilaženje IdentityGuard provere u netipičnim sredinama.</li><li><strong>Status:</strong> 🟢 Aktivno i Verifikovano.</li></ul><h3 id="_2-sop-002-dijagnostika-otklanjanje-gresaka-troubleshooting" tabindex="-1">2. <a href="/sop/troubleshooting">SOP-002: Dijagnostika &amp; Otklanjanje Grešaka (Troubleshooting)</a> <a class="header-anchor" href="#_2-sop-002-dijagnostika-otklanjanje-gresaka-troubleshooting" aria-label="Permalink to &quot;2. [SOP-002: Dijagnostika &amp; Otklanjanje Grešaka (Troubleshooting)](/sop/troubleshooting)&quot;">​</a></h3><p>Priručnik za rešavanje vanrednih stanja u sistemu, ručnu popravku SQLite baza, detekciju curenja LLM tokena i konfigurisanje self-healing parametara.</p><ul><li><strong>Ključne teme:</strong> Reset ELO rejtinga agenata, otključavanje baze pod lock-om, i analiza trace logova u <code>storage/traces/</code> direktorijumu.</li><li><strong>Status:</strong> 🟢 Aktivno i Verifikovano.</li></ul><hr><h2 id="🛡️-sigurnosna-pravila-za-operatere" tabindex="-1">🛡️ Sigurnosna Pravila za Operatere <a class="header-anchor" href="#🛡️-sigurnosna-pravila-za-operatere" aria-label="Permalink to &quot;🛡️ Sigurnosna Pravila za Operatere&quot;">​</a></h2><p>Pre pokretanja bilo koje operativne procedure, uverite se da se pridržavate sledećih pravila:</p><ol><li><strong>Nema produkcionih ključeva u kodu:</strong> Svi API ključevi za Gemini i MongoDB URI moraju biti prosleđeni isključivo kroz enkriptovane env tajne (npr. Google Cloud Secret Manager).</li><li><strong>Obavezan backup pre ELO resetovanja:</strong> Ručne manipulacije nad SQLite bazom u cilju menjanja ELO ocena agenata moraju biti praćene kreiranjem kopije datoteke (<code>cp storage/memory.db storage/memory_backup.db</code>).</li><li><strong>Analiza logova pre ručnih patch-eva:</strong> Uvek proverite trace izveštaje neuspešnog workflow-a pre pokretanja ručnih commands, kako biste videli dijagnozu Critic agenta.</li></ol>',15)])])}const v=e(t,[["render",n]]);export{k as __pageData,v as default};
